prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "01e9c28ede6a4695b91dd90b3e0c5f1b" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask .
  OPTIONAL { ?task bbo:name ?taskName }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName (COUNT(DISTINCT ?messageFlow) AS ?messageCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "01e9c28ede6a4695b91dd90b3e0c5f1b" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bbo:id ?taskId .

  ?messageFlow a bboExt:MessageFlow ;
               tai:belongsTo ?choreo .

  # Check if the message flow references the task ID
  FILTER(bboExt:sourceRef = ?taskId || bboExt:targetRef = ?taskId)
}
GROUP BY ?taskName
HAVING (COUNT(DISTINCT ?messageFlow) = 2)
